FUNCTION_BLOCK TON
VAR_INPUT
IN : BOOL;
PT : DINT; 
CYCLE_TIME : DINT; 
END_VAR
VAR_OUTPUT
Q : BOOL;
ET : DINT; 
END_VAR
VAR
elapsedTimeInternal : DINT := 0; 
IN_PREV : BOOL := FALSE;
END_VAR

IF IN THEN
IF NOT IN_PREV THEN
elapsedTimeInternal := 0;
END_IF;

IF elapsedTimeInternal < PT THEN
elapsedTimeInternal := elapsedTimeInternal + CYCLE_TIME;
Q := FALSE;
ELSE
elapsedTimeInternal := PT;
Q := TRUE;
END_IF;

ET := elapsedTimeInternal;
ELSE
Q := FALSE;
ET := 0;
elapsedTimeInternal := 0;
END_IF;
IN_PREV := IN;
END_FUNCTION_BLOCK

