VAR
    state : INT;
    prevState : INT;

    MaterialQueue : ARRAY[1..10] OF INT;
    QueueHead : INT := 1;
    QueueTail : INT := 1;
    QueueCount : INT := 0;

    AGVPosition : ARRAY[1..3] OF INT := [0, 0, 0];
    AGVStatus : ARRAY[1..3] OF BOOL := [TRUE, TRUE, TRUE];
    AGVTaskID : ARRAY[1..3] OF INT := [0, 0, 0];

    i : INT;
    SelectedAGV : INT;
    PriorityLogic : BOOL;
    NextState : INT;
END_VAR
BEGIN
    IF prevState = 0 THEN
        prevState := state;
    END_IF;

    IF state = 0 THEN
        IF MaterialRequest < 0 THEN
            NextState := 5;
            InvalidRequestError := TRUE;
        ELSE
            IF QueueCount < 10 THEN
                NextState := 1;
                OverflowError := FALSE;
            ELSE
                NextState := 5;
                OverflowError := TRUE;
            END_IF;
        END_IF;
    END_IF;

    IF state = 1 THEN
        PriorityLogic := FALSE;
        SelectedAGV := 0;

        IF AGVStatus[1] = TRUE THEN
            SelectedAGV := 1;
            PriorityLogic := TRUE;
        ELSIF AGVStatus[2] = TRUE THEN
            SelectedAGV := 2;
            PriorityLogic := TRUE;
        ELSIF AGVStatus[3] = TRUE THEN
            SelectedAGV := 3;
            PriorityLogic := TRUE;
        END_IF;

        IF PriorityLogic = TRUE THEN
            NextState := 2;
        ELSE
            NextState := 0;
        END_IF;
    END_IF;

    IF state = 2 THEN
        IF SelectedAGV > 0 THEN
            AGVStatus[SelectedAGV] := FALSE;

            IF QueueHead <= QueueTail THEN
                AGVTaskID[SelectedAGV] := MaterialQueue[QueueHead];
                QueueHead := QueueHead + 1;
                QueueCount := QueueCount - 1;
